class CustomAuthorizationCodeServices extends InMemoryAuthorizationCodeServices {
    private final Map<String, CodeEntry> codes = new ConcurrentHashMap<>();
    private final ScheduledExecutorService scheduler = Executors.newScheduledThreadPool(1);

    public CustomAuthorizationCodeServices() {
        scheduler.scheduleAtFixedRate(this::cleanupExpiredCodes, 1, 1, TimeUnit.MINUTES);
    }

    @Override
    public String createAuthorizationCode() {
        String code = super.createAuthorizationCode();
        codes.put(code, new CodeEntry(code, System.currentTimeMillis()));
        return code;
    }

    @Override
    public void remove(String code) {
        codes.remove(code);
    }

    private void cleanupExpiredCodes() {
        long currentTime = System.currentTimeMillis();
        codes.entrySet().removeIf(entry -> currentTime - entry.getValue().getTimestamp() > 600000);
    }

    static class CodeEntry {
        private final String code;
        private final long timestamp;

        public CodeEntry(String code, long timestamp) {
            this.code = code;
            this.timestamp = timestamp;
        }

        public String getCode() {
            return code;
        }

        public long getTimestamp() {
            return timestamp;
        }
    }
}

@RestController
class AuthorizationController {

    @GetMapping("/oauth/authorize")
    public String authorize(
            @RequestParam("client_id") String clientId,
            @RequestParam("redirect_uri") String redirectUri,
            @RequestParam("response_type") String responseType,
            @RequestParam("scope") String scope) {
        
        if (!validateRedirectUri(clientId, redirectUri)) {
            return "Invalid redirect_uri";
        }
        
        return "Authorization successful for client: " + clientId;
    }

    private boolean validateRedirectUri(String clientId, String redirectUri) {
        Map<String, String> clientRedirects = getClientRedirectUris(clientId);
        for (String registeredUri : clientRedirects.values()) {
            if (isUriMatch(registeredUri, redirectUri)) {
                return true;
            }
        }
        return false;
    }

    private boolean isUriMatch(String registeredUri, String redirectUri) {
        try {
            String[] registeredParts = registeredUri.split("/");
            String[] redirectParts = redirectUri.split("/");
            
            if (registeredParts.length < 3 || redirectParts.length < 3) return false;
            
            if (!registeredParts[0].equals(redirectParts[0])) return false;
            if (!registeredParts[1].equals(redirectParts[1])) return false;
            
            String registeredHost = registeredParts[2];
            String redirectHost = redirectParts[2];
            
            if (registeredHost.equals(redirectHost)) return true;
            
            if (registeredHost.startsWith("*.")) {
                String baseDomain = registeredHost.substring(2);
                if (redirectHost.endsWith("." + baseDomain)) return true;
            }
            
            return false;
        } catch (Exception e) {
            return false;
        }
    }

    private Map<String, String> getClientRedirectUris(String clientId) {
        Map<String, String> redirects = new HashMap<>();
        redirects.put("client-app", "https://*.example.com/*");
        redirects.put("client-app", "http://localhost:8080/*");
        return redirects;
    }
}